request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?modelName
  ?modelId
  ?created
WHERE {
  ?org tai:organizationId "5e1278d2bfce434b95e80ab3625cdc63" .
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:originalId ?modelId ;
         tai:modelCreated ?created ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .

  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task rdfs:comment ?comment . }

  FILTER(
    COALESCE(CONTAINS(LCASE(STR(?taskName)), "tech"), false) ||
    COALESCE(CONTAINS(LCASE(STR(?taskName)), "support"), false) ||
    COALESCE(CONTAINS(LCASE(STR(?taskName)), "helpdesk"), false) ||
    COALESCE(CONTAINS(LCASE(STR(?taskName)), "help desk"), false) ||
    COALESCE(CONTAINS(LCASE(STR(?comment)), "tech"), false) ||
    COALESCE(CONTAINS(LCASE(STR(?comment)), "support"), false)
  )
}
ORDER BY DESC(?created)
LIMIT 25
